import java.io.*;
import java.util.HashMap;
import java.util.Map;

public class DiskCache {
    private final String cacheDirectory;

    public DiskCache(String cacheDirectory) {
        this.cacheDirectory = cacheDirectory;
        File directory = new File(cacheDirectory);
        if (!directory.exists()) {
            directory.mkdirs();
        }
    }

    public void put(String key, Object value) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(new File(cacheDirectory, key)))) {
            oos.writeObject(value);
        }
    }

    public Object get(String key) throws IOException, ClassNotFoundException {
        File file = new File(cacheDirectory, key);
        if (!file.exists()) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(file))) {
            return ois.readObject();
        }
    }

    public void remove(String key) {
        File file = new File(cacheDirectory, key);
        if (file.exists()) {
            file.delete();
        }
    }

    public boolean containsKey(String key) {
        return new File(cacheDirectory, key).exists();
    }

    public static void main(String[] args) {
        try {
            DiskCache cache = new DiskCache("cache");

            // Example usage with complex object
            Map<String, String> userPreferences = new HashMap<>();
            userPreferences.put("theme", "dark");
            userPreferences.put("language", "en");

            cache.put("user1", userPreferences);

            Map<String, String> retrievedPreferences = (Map<String, String>) cache.get("user1");
            System.out.println(retrievedPreferences);

            cache.remove("user1");

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}